catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
   if (isLoading || newValue == '') {
      return;
   }

    // 👇 ضعي sys_id بتاع medicines_order هنا
    var mrvsValue = g_form.getValue('IO:94cecc8347c947d0516b5ac5316d43cf');
	console.log(mrvsValue);

    if (!mrvsValue) {
        g_form.setValue('total_order_price', '');
        return;
    }

    // دالة لاستخراج أول رقم (عدد صحيح أو عشري) من النص
    function extractNumber(str) {
        if (str === undefined || str === null) return 0;
        var strValue = str.toString();
        var match = strValue.match(/(\d+(?:\.\d+)?)/);
        return match ? parseFloat(match[1]) : 0;
    }

    try {
        var rows = JSON.parse(mrvsValue);
        var total = 0;

        for (var i = 0; i < rows.length; i++) {
            var subtotal = extractNumber(rows[i].subtotal_price);
            total += subtotal;
        }

        g_form.setValue('total_order_price', total.toFixed(2) + ' EGP');
    } catch(e) {
        console.error('Error parsing MRVS: ' + e.message);
    }
}
